with.script:
const webhookUrl = process.env.WEBHOOK_URL;
if (!webhookUrl) {
  core.info('DISCORD_ADVISORY_WEBHOOK not set - skipping');
  return;
}

const { data: allItems } = await github.rest.issues.listForRepo({
  owner: context.repo.owner,
  repo: context.repo.repo,
  labels: 'stale',
  state: 'open',
  per_page: 100,
});

// Filter out PRs (listForRepo returns both issues and PRs)
const issues = allItems.filter(i => !i.pull_request);

if (issues.length === 0) {
  core.info('No stale issues.');
  return;
}

const lines = issues.slice(0, 15).map(i => {
  const labels = i.labels.map(l => l.name).filter(n => n !== 'stale').join(', ');
  return `- [#${i.number} ${i.title}](${i.html_url}) (${labels})`;
});

const extra = issues.length > 15 ? `\n...and ${issues.length - 15} more` : '';

const body = JSON.stringify({
  embeds: [{
    title: `Weekly stale digest: ${issues.length} issue(s)`,
    description: lines.join('\n') + extra +
      '\n\nReview these and decide: revive, reassign, or close.',
    color: 10038562,  // dark red
  }],
});

const resp = await fetch(webhookUrl, {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body,
});
if (!resp.ok) {
  core.setFailed(`Discord webhook failed: ${resp.status} ${await resp.text()}`);
} else {
  core.info(`Discord response: ${resp.status}`);
}
